from flask import Flask, request, redirect, url_for
from flask_oidc import OpenIDConnect

app = Flask(__name__)
app.config["SECRET_KEY"] = "your-secret-key"
app.config["OIDC_CLIENT_SECRETS"] = "/path/to/client_secrets.json"
oidc = OpenIDConnect(app)

@app.route("/")
def index():
    return redirect(url_for("authorize"))

@app.route("/authorize")
def authorize():
    authorization_url, state = oidc.authorization_url(
        client_id=app.config["OIDC_CLIENT_ID"],
        redirect_uri=request.base_url + "/callback",
        scope="openid",
        response_type="id_token"
    )
    return redirect(authorization_url)

@app.route("/callback")
def callback():
    id_token = request.args["id_token"]
    userinfo = oidc.userinfo(id_token)
    # handle the userinfo object as needed
    return "User authenticated"